-- ============================================================
-- NEW TOOLS: goose, cline, kiro, gh-copilot, qoder, trae, kilo-code
-- Append to seed.sql and run on server:
--   sudo docker exec -i atlas-mysql mysql -u root -proot ai_command_atlas < scripts/seed-new-tools.sql
-- ============================================================

SET NAMES utf8mb4;
USE ai_command_atlas;

-- New tools
ON DUPLICATE KEY UPDATE
  name=VALUES(name), company=VALUES(company), description=VALUES(description),
  description_zh=VALUES(description_zh), color=VALUES(color), github_url=VALUES(github_url), docs_url=VALUES(docs_url);

-- ── Goose commands ──────────────────────────────────────────
SET @gs = (SELECT id FROM tools WHERE slug = 'goose');

ON DUPLICATE KEY UPDATE description=VALUES(description), description_zh=VALUES(description_zh), syntax=VALUES(syntax), last_checked=VALUES(last_checked);

-- ── Cline commands ──────────────────────────────────────────
SET @cl = (SELECT id FROM tools WHERE slug = 'cline');

